class Solution {
    public boolean makeStringsEqual(String s, String target) {
        int count1S = 0, count1Target = 0;
        for (int i = 0; i < s.length(); i++) {
            if (s.charAt(i) == '1') count1S++;
            if (target.charAt(i) == '1') count1Target++;
        }
        if (count1S == count1Target) {
            if (count1S == 0 || count1S == s.length()) return true;
            return true;
        }
        return count1S == count1Target;
    }
}
